const project = $('Load Project Data').first().json;
const briefing = $('Load Approved Briefing').first().json;
const promptData = $('Load Agent Prompt').first().json;
const projectId = $('Receive Project').first().json.project_id;
const systemPrompt = (promptData && promptData.content) ? promptData.content : 'Eres el Agente de Distribucion de un estudio de arquitectura tecnica. Genera 2-3 opciones de redistribucion significativamente diferentes. Responde EXCLUSIVAMENTE con un array JSON valido sin backticks.';
const model = (promptData && promptData.model_recommended) || 'gpt-4o';
const temperature = (promptData && promptData.temperature !== null && promptData.temperature !== undefined) ? Number(promptData.temperature) : 0.5;
const clientNeeds = (briefing.client_needs || []).map(function(n) { return typeof n === 'object' ? (n.need || JSON.stringify(n)) : String(n); }).join('\n- ');
const constraints = (briefing.constraints || []).map(function(c) { return typeof c === 'object' ? ('[' + (c.type || '') + '] ' + (c.description || '')) : String(c); }).join('\n- ');
const location = [project.location_city, project.location_province].filter(Boolean).join(', ') || 'No especificada';
const userParts = ['Genera 2-3 opciones de redistribucion para este proyecto.', '', 'BRIEFING APROBADO:', 'Resumen: ' + (briefing.summary || 'No disponible'), '', 'Necesidades del cliente:', '- ' + (clientNeeds || 'No especificadas'), '', 'Restricciones criticas:', '- ' + (constraints || 'Ninguna'), '', 'INMUEBLE:', '- Tipo: ' + (project.property_type || 'No especificado'), '- Superficie: ' + (project.property_area_m2 ? project.property_area_m2 + ' m2' : 'No especificada'), '- Localizacion: ' + location, '', 'PRESUPUESTO: ' + (project.budget_target ? project.budget_target + ' EUR' : 'No especificado'), '', 'Responde con un array JSON de 2-3 opciones. Cada opcion: option_number (1,2,3), title, description, intervention_logic, rooms_layout (array), technical_notes (array), conflict_points (array), pros (array), cons (array), estimated_complexity (baja/media/alta).'];
const userPrompt = userParts.join('\n');
return [{ json: { project_id: projectId, project_name: project.project_name, client_name: project.client_name, prompt_system: systemPrompt, prompt_user: userPrompt, model: model, temperature: temperature } }];

const llmResult = $input.first().json;
const preparedData = $('Prepare LLM Payload').first().json;
let responseText = (llmResult.response_text || '').trim();
if (responseText.startsWith('```')) {
  responseText = responseText.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim();
}
let options;
try {
  const parsed = JSON.parse(responseText);
  options = Array.isArray(parsed) ? parsed : (parsed.options || [parsed]);
} catch(e) {
  options = [{ option_number: 1, title: 'Error - Revision manual requerida', description: responseText.substring(0, 300), intervention_logic: '', rooms_layout: [], technical_notes: [], conflict_points: [], pros: [], cons: [], estimated_complexity: 'media' }];
}
return options.slice(0, 3).map(function(opt, idx) {
  return { json: { project_id: preparedData.project_id, project_name: preparedData.project_name, client_name: preparedData.client_name, option_number: opt.option_number || (idx + 1), title: opt.title || ('Opcion ' + (idx + 1)), description: opt.description || '', intervention_logic: opt.intervention_logic || '', rooms_layout: opt.rooms_layout || [], technical_notes: opt.technical_notes || [], conflict_points: opt.conflict_points || [], pros: opt.pros || [], cons: opt.cons || [], estimated_complexity: opt.estimated_complexity || 'media' } };
});

const allItems = $input.all();
const preparedData = $('Prepare LLM Payload').first().json;
const options = allItems.map(function(item) { return { id: item.json.id, option_number: item.json.option_number, title: item.json.title }; });
return [{ json: { project_id: preparedData.project_id, project_name: preparedData.project_name, client_name: preparedData.client_name, options: options, option_count: options.length } }];

const collected = $('Collect All Options').first().json;
const parsedOptions = $('Parse Design Options').all();
const approvalRecord = $('Create Approval').first().json;
const resumeUrl = $execution.resumeUrl;
const optionButtons = collected.options.map(function(opt) {
  const selectUrl = resumeUrl + '?option=' + opt.option_number;
  return '<a href="' + selectUrl + '" style="background:#2980b9;color:white;padding:12px 20px;text-decoration:none;border-radius:4px;margin:6px;display:inline-block">Seleccionar Opcion ' + opt.option_number + '</a>';
}).join(' ');
const optionCards = parsedOptions.map(function(item) {
  const opt = item.json;
  const prosList = (opt.pros || []).map(function(p) { return '<li>' + String(p) + '</li>'; }).join('');
  const consList = (opt.cons || []).map(function(c) { return '<li>' + String(c) + '</li>'; }).join('');
  return '<div style="border:1px solid #ddd;border-radius:8px;padding:16px;margin-bottom:16px">'
    + '<h3 style="color:#2c3e50;margin-top:0">Opcion ' + opt.option_number + ': ' + (opt.title || '') + '</h3>'
    + '<p>' + (opt.description || '') + '</p>'
    + '<p><b>Complejidad:</b> ' + (opt.estimated_complexity || '') + '</p>'
    + '<h4>Ventajas:</h4><ul>' + prosList + '</ul>'
    + '<h4>Inconvenientes:</h4><ul>' + consList + '</ul>'
    + '</div>';
}).join('');
const htmlBody = '<div style="font-family:Arial,sans-serif;max-width:750px;margin:0 auto">'
  + '<h2 style="color:#2c3e50">Studio AI - Opciones de Distribucion</h2>'
  + '<h3 style="color:#7f8c8d">Proyecto: ' + collected.project_name + '</h3>'
  + '<p><b>Cliente:</b> ' + collected.client_name + '</p>'
  + '<hr style="border:none;border-top:1px solid #eee">'
  + optionCards
  + '<div style="text-align:center;margin:32px 0">'
  + '<p><b>Selecciona la opcion a desarrollar:</b></p>'
  + optionButtons
  + '</div>'
  + '<p style="color:#95a5a6;font-size:12px;text-align:center">Este enlace expira en 72 horas.</p>'
  + '</div>';
return [{ json: { to: 'arquitecto@estudio.com', subject: '[Studio AI] Opciones de distribucion: ' + collected.project_name, html_body: htmlBody, project_id: collected.project_id, project_name: collected.project_name, option_count: collected.option_count } }];

const resumeData = $input.first().json;
const emailData = $('Build Selection Email').first().json;
const approvalData = $('Create Approval').first().json;
const option = (resumeData.query && resumeData.query.option) || (resumeData.body && resumeData.body.option) || resumeData.option || '1';
const optionNumber = parseInt(String(option), 10) || 1;
return [{ json: { option_number: optionNumber, project_id: emailData.project_id, project_name: emailData.project_name, approval_id: approvalData.id } }];
